def select_best_resolution(original_size, possible_resolutions):
    def select_best_resolution(original_size, possible_resolutions):
        best_resolution = None
        best_aspect_ratio_diff = float('inf')
        for resolution in possible_resolutions:
            aspect_ratio = resolution[0] / resolution[1]
            original_aspect_ratio = original_size[0] / original_size[1]
            aspect_ratio_diff = abs(aspect_ratio - original_aspect_ratio)
            if aspect_ratio_diff < best_aspect_ratio_diff:
                best_aspect_ratio_diff = aspect_ratio_diff
                best_resolution = resolution
        return best_resolution

