def last_before(val, arr):
    import numpy as np
    def last_before(val, arr):
        left, right = 0, len(arr) - 1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] <= val:
                if mid == len(arr) - 1 or arr[mid + 1] > val:
                    return mid
                left = mid + 1
            else:
                right = mid - 1
        return -1

